1	/**
2	 * POST /api/upload/signed/finalize/:id
3	 *
4	 * Step 2 of 2 for direct-to-storage uploads. Called by the client
5	 * after it has successfully PUT the file bytes to the signed URL
6	 * from /api/upload/signed/prepare. This endpoint:
7	 *
8	 *   1. verifies the Upload row belongs to the caller;
9	 *   2. HEADs the object in Supabase Storage to confirm the PUT
10	 *      actually landed — stops a malicious client from POSTing to
11	 *      /finalize without uploading anything;
12	 *   3. for **audio** rows, sets `Upload.audioUrl` to the public URL
13	 *      so /post/[slug] renders the <audio> player;
14	 *   4. for **text-extractable** rows (PDF / DOCX / txt / md / vtt /
15	 *      jsonl / json), fetches the bytes back from Storage and runs
16	 *      `extractText` to populate `Upload.textContent` — identical
17	 *      to the inline /api/upload path, just with the bytes coming
18	 *      from Storage instead of the request body;
19	 *   5. fires the Noosphere ingest dispatch so the backend pipeline
20	 *      (Whisper for audio; LLM claim extraction for all) runs.
21	 *
22	 * All steps are idempotent: a retry on an already-finalized row
23	 * returns 200 with the existing state rather than erroring.
24	 */
25	import { NextResponse } from "next/server";
26	import { getFounderFromAuth } from "@/lib/apiKeyAuth";
27	import { db } from "@/lib/db";
28	import { extractText } from "@/lib/extractText";
29	import { canWrite, WRITE_FORBIDDEN_RESPONSE } from "@/lib/roles";
30	import { sanitizeAndCap } from "@/lib/sanitizeText";
31	import {
32	  audioObjectExists,
33	  getPublicAudioUrl,
34	  isAudioStorageConfigured,
35	} from "@/lib/supabaseStorage";
36	import { triggerNoosphereProcessing } from "@/lib/triggerNoosphereProcessing";
37	
38	const AUDIO_MIME_OR_EXT = /^(audio\/|.*\.(mp3|m4a|wav|webm|ogg|aac)$)/i;
39	
40	function isAudioUpload(mimeType: string, originalName: string): boolean {
41	  return (
42	    mimeType.toLowerCase().startsWith("audio/") ||
43	    AUDIO_MIME_OR_EXT.test(originalName.toLowerCase())
44	  );
45	}
46	
47	/**
48	 * Server-side download of an object we just uploaded via the signed
49	 * URL. Supabase serves public buckets at /object/public/<bucket>/<path>
50	 * without auth, so we can just fetch the public URL. For larger
51	 * files (50+ MB) this re-downloads inside the Vercel function, which
52	 * is fine for text extraction — PDFs and DOCX extract in under a
53	 * minute even at several hundred MB.
54	 *
55	 * Guarded by a size cap so a pathological 500 MB PDF doesn't blow
56	 * the Vercel function's memory — for files bigger than this, we
57	 * skip extraction and leave `textContent` null. The file is still
58	 * uploaded + available; Noosphere just has to wait for a machine
59	 * with enough RAM to extract it later.
60	 */
61	const TEXT_EXTRACTION_MAX_BYTES = 80 * 1024 * 1024;
62	
63	async function extractFromStorage(
64	  publicUrl: string,
65	  originalName: string,
66	  mimeType: string,
67	  expectedSize: number,
68	): Promise<{
69	  textContent: string | null;
70	  note: string;
71	  hardFailed: boolean;
72	}> {
73	  if (expectedSize > TEXT_EXTRACTION_MAX_BYTES) {
74	    return {
75	      textContent: null,
76	      note:
77	        `File is ${(expectedSize / 1024 / 1024).toFixed(1)} MB — above ` +
78	        `the ${(TEXT_EXTRACTION_MAX_BYTES / 1024 / 1024).toFixed(0)} MB ` +
79	        `server-side extraction cap. Upload saved; run a local Noosphere ` +
80	        `ingest to extract text from the stored file.`,
81	      hardFailed: false,
82	    };
83	  }
84	  try {
85	    const res = await fetch(publicUrl);
86	    if (!res.ok) {
87	      return {
88	        textContent: null,
89	        note: `Couldn't fetch uploaded file back from Storage (HTTP ${res.status}).`,
90	        hardFailed: true,
91	      };
92	    }
93	    const ab = await res.arrayBuffer();
94	    const buffer = Buffer.from(ab);
95	    const result = await extractText(buffer, originalName, mimeType);
96	    return {
97	      textContent: result.textContent,
98	      note: result.note,
99	      hardFailed: result.hardFailed,
100	    };
101	  } catch (err) {
102	    return {
103	      textContent: null,
104	      note: `Storage fetch failed: ${err instanceof Error ? err.message : String(err)}`,
105	      hardFailed: true,
106	    };
107	  }
108	}
109	
110	export async function POST(
111	  req: Request,
112	  { params }: { params: Promise<{ id: string }> },
113	) {
114	  try {
115	    const founder = await getFounderFromAuth(req);
116	    if (!founder) {
117	      return NextResponse.json(
118	        { error: "Not authenticated" },
119	        { status: 401 },
120	      );
121	    }
122	    // Defence-in-depth: viewers shouldn't reach here (prepare gates
123	    // them at step 1) but if they did via a stale URL or by replaying
124	    // an old request, finalize must also reject.
125	    if (!canWrite(founder.role)) {
126	      return NextResponse.json(WRITE_FORBIDDEN_RESPONSE, { status: 403 });
127	    }
128	    if (!isAudioStorageConfigured()) {
129	      return NextResponse.json(
130	        { error: "Supabase Storage not configured." },
131	        { status: 501 },
132	      );
133	    }
134	
135	    const { id } = await params;
136	    const body = (await req.json().catch(() => ({}))) as {
137	      audioDurationSec?: number;
138	      // Optional overrides for late-arriving metadata. Dialectic's
139	      // usual path seeds `transcript` at /prepare, so these two are
140	      // rarely used — they exist for re-transcribed sessions where the
141	      // final transcript differs from the one sent at prepare time.
142	      transcript?: string;
143	      extractionMethod?: string;
144	      fileSize?: number;
145	    };
146	
147	    const upload = await db.upload.findUnique({
148	      where: { id },
149	      select: {
150	        id: true,
151	        organizationId: true,
152	        founderId: true,
153	        filePath: true,
154	        status: true,
155	        audioUrl: true,
156	        textContent: true,
157	        originalName: true,
158	        mimeType: true,
159	        fileSize: true,
160	      },
161	    });
162	    if (!upload) {
163	      return NextResponse.json({ error: "Upload not found" }, { status: 404 });
164	    }
165	    if (upload.organizationId !== founder.organizationId) {
166	      return NextResponse.json({ error: "Forbidden" }, { status: 403 });
167	    }
168	    if (upload.founderId !== founder.id) {
169	      return NextResponse.json(
170	        { error: "Only the uploader can finalize their own upload." },
171	        { status: 403 },
172	      );
173	    }
174	
175	    // Extract the object path from the `filePath = storage:<path>`
176	    // sentinel. If someone tampered with the row or this wasn't a
177	    // storage-backed upload, we refuse.
178	    const prefix = "storage:";
179	    if (!upload.filePath || !upload.filePath.startsWith(prefix)) {
180	      return NextResponse.json(
181	        {
182	          error:
183	            "This upload isn't a storage-backed row. Use /api/upload for small inline files.",
184	        },
185	        { status: 400 },
186	      );
187	    }
188	    const objectPath = upload.filePath.slice(prefix.length);
189	
190	    const isAudio = isAudioUpload(upload.mimeType, upload.originalName);
191	
192	    // Idempotent: already finalized. Return current state.
193	    const alreadyFinalized =
194	      (isAudio && upload.audioUrl) ||
195	      (!isAudio && upload.textContent);
196	    if (alreadyFinalized) {
197	      return NextResponse.json({
198	        ok: true,
199	        alreadyFinalized: true,
200	        audioUrl: upload.audioUrl,
201	      });
202	    }
203	
204	    // Verify the bytes are actually in Storage. Without this a
205	    // malicious client could POST to /finalize without a real PUT.
206	    const exists = await audioObjectExists(objectPath);
207	    if (!exists) {
208	      return NextResponse.json(
209	        {
210	          error:
211	            "File not present in storage yet. Complete the PUT to the signed URL from /prepare, then retry finalize.",
212	        },
213	        { status: 409 },
214	      );
215	    }
216	
217	    const publicUrl = getPublicAudioUrl(objectPath);
218	    const duration =
219	      isAudio &&
220	      body.audioDurationSec &&
221	      Number.isFinite(body.audioDurationSec)
222	        ? Math.max(0, Math.floor(body.audioDurationSec))
223	        : undefined;
224	
225	    // Updates built up conditionally. For audio we set `audioUrl`.
226	    // For non-audio we run extraction here so `textContent` is ready
227	    // by the time Noosphere picks the row up.
228	    const data: Record<string, unknown> = {
229	      processLog: {
230	        set: sanitizeAndCap(
231	          [
232	            `— Direct upload reserved —`,
233	            `— PUT confirmed in storage (${objectPath}) —`,
234	            isAudio
235	              ? `— Audio ready; queued for transcription —`
236	              : `— File ready; running server-side extraction —`,
237	          ].join("\n"),
238	          8_000,
239	        ),
240	      },
241	    };
242	
243	    // Late-arriving transcript override. Rare — Dialectic normally
244	    // attaches the transcript at /prepare — but if the client
245	    // re-transcribed after the PUT landed, allow the newer text to
246	    // replace whatever was seeded earlier. For text-extractable rows
247	    // a late override also lets the caller bypass the server-side
248	    // extractor entirely.
249	    const lateTranscript =
250	      typeof body.transcript === "string" && body.transcript.trim().length > 0
251	        ? sanitizeAndCap(body.transcript, 2_000_000)
252	        : null;
253	    const lateExtraction =
254	      typeof body.extractionMethod === "string" &&
255	      body.extractionMethod.trim()
256	        ? sanitizeAndCap(body.extractionMethod, 64)
257	        : null;
258	
259	    if (isAudio) {
260	      data.audioUrl = publicUrl;
261	      if (duration !== undefined) data.audioDurationSec = duration;
262	      if (lateTranscript) {
263	        data.textContent = lateTranscript;
264	        if (lateExtraction) data.extractionMethod = lateExtraction;
265	        // If textContent is now populated, the row is ready for claim
266	        // extraction only — ingest-from-codex will skip Whisper.
267	        data.status = "awaiting_ingest";
268	      }
269	    } else if (lateTranscript) {
270	      // Non-audio with a caller-supplied transcript: trust it, skip
271	      // the server-side extractor entirely. Useful for
272	      // already-extracted text that the client wants persisted under
273	      // the same Upload row.
274	      data.textContent = lateTranscript;
275	      if (lateExtraction) data.extractionMethod = lateExtraction;
276	      const suffix = `— Extraction: caller-supplied (method=${lateExtraction ?? "unspecified"}) —\n`;
277	      (data.processLog as { set: string }).set = sanitizeAndCap(
278	        (data.processLog as { set: string }).set + "\n" + suffix,
279	        8_000,
280	      );
281	    } else {
282	      // Non-audio: fetch back + extract. For text uploads the bytes
283	      // are small and this runs in well under a second; for PDFs /
284	      // DOCX it's typically 1–5s. Results land directly in the
285	      // Upload row so Noosphere can ingest without another round-
286	      // trip.
287	      const extraction = await extractFromStorage(
288	        publicUrl!,
289	        upload.originalName,
290	        upload.mimeType,
291	        upload.fileSize,
292	      );
293	      data.textContent = extraction.textContent;
294	      const suffix = `— Extraction: ${extraction.note} —\n`;
295	      (data.processLog as { set: string }).set = sanitizeAndCap(
296	        (data.processLog as { set: string }).set + "\n" + suffix,
297	        8_000,
298	      );
299	      if (extraction.hardFailed) {
300	        data.errorMessage = sanitizeAndCap(extraction.note, 2_000);
301	      }
302	    }
303	
304	    const updated = await db.upload.update({
305	      where: { id },
306	      data,
307	      select: {
308	        id: true,
309	        audioUrl: true,
310	        audioDurationSec: true,
311	        textContent: true,
312	        slug: true,
313	        publishedAt: true,
314	      },
315	    });
316	
317	    // Kick off the Codex → Noosphere pipeline.
318	    triggerNoosphereProcessing(id, {
319	      organizationId: founder.organizationId,
320	      withLlm: true,
321	    }).catch((err) => {
322	      console.error(`signed finalize dispatch for ${id} failed:`, err);
323	    });
324	
325	    await db.auditEvent
326	      .create({
327	        data: {
328	          organizationId: founder.organizationId,
329	          founderId: founder.id,
330	          uploadId: id,
331	          action: isAudio ? "audio_upload_finalized" : "file_upload_finalized",
332	          detail:
333	            `Direct upload persisted at ${objectPath}; dispatched for processing`,
334	        },
335	      })
336	      .catch(() => {
337	        /* non-fatal */
338	      });
339	
340	    return NextResponse.json({
341	      ok: true,
342	      isAudio,
343	      audioUrl: updated.audioUrl,
344	      audioDurationSec: updated.audioDurationSec,
345	      textContentChars: updated.textContent?.length ?? 0,
346	      publicUrl: updated.slug ? `/post/${updated.slug}` : null,
347	      published: Boolean(updated.publishedAt),
348	    });
349	  } catch (err) {
350	    console.error("upload/signed/finalize error:", err);
351	    return NextResponse.json(
352	      {
353	        error: `Finalize failed: ${err instanceof Error ? err.message : "unknown error"}`,
354	      },
355	      { status: 500 },
356	    );
357	  }
358	}
